/// 표 셀 내부에 중첩 표를 삽입한다 (네이티브).
///
/// create_table_native와 동일한 패턴을 따르지만 본문 문단 대신
/// `sections[section_idx].paragraphs[parent_para_idx].controls[control_idx]` 의
/// Table::cells[cell_idx].paragraphs 에 표를 삽입한다.
///
/// 반환: JSON `{"ok":true,"cellParaIdx":<N>,"controlIdx":0}`
pub fn create_table_in_cell_native(
    &mut self,
    section_idx: usize,
    parent_para_idx: usize,
    control_idx: usize,
    cell_idx: usize,
    cell_para_idx: usize,
    char_offset: usize,
    row_count: u16,
    col_count: u16,
) -> Result<String, HwpError> {
    use crate::model::table::{Table, Cell, TablePageBreak};
    use crate::model::paragraph::{CharShapeRef, LineSeg};
    use crate::model::style::{BorderFill, BorderLine, BorderLineType, DiagonalLine, Fill};

    if section_idx >= self.document.sections.len() {
        return Err(HwpError::RenderError(format!(
            "구역 인덱스 {} 범위 초과", section_idx
        )));
    }
    if parent_para_idx >= self.document.sections[section_idx].paragraphs.len() {
        return Err(HwpError::RenderError(format!(
            "부모 문단 인덱스 {} 범위 초과", parent_para_idx
        )));
    }
    if row_count == 0 || col_count == 0 || col_count > 256 {
        return Err(HwpError::RenderError(format!(
            "행/열 수 범위 오류 (행={}, 열={})", row_count, col_count
        )));
    }

    // --- 1. 부모 셀에서 컨텍스트 읽기 (불변 참조) ---
    let (parent_cell_width, parent_cell_pad_l, parent_cell_pad_r,
         default_char_shape_id, default_para_shape_id) = {
        let parent_para = &self.document.sections[section_idx].paragraphs[parent_para_idx];
        if control_idx >= parent_para.controls.len() {
            return Err(HwpError::RenderError(format!(
                "컨트롤 인덱스 {} 범위 초과", control_idx
            )));
        }
        let parent_table = match &parent_para.controls[control_idx] {
            Control::Table(t) => t,
            _ => return Err(HwpError::RenderError(
                "지정된 컨트롤이 표가 아닙니다".to_string()
            )),
        };
        if cell_idx >= parent_table.cells.len() {
            return Err(HwpError::RenderError(format!(
                "셀 인덱스 {} 범위 초과 (총 {}개)", cell_idx, parent_table.cells.len()
            )));
        }
        let parent_cell = &parent_table.cells[cell_idx];
        if cell_para_idx >= parent_cell.paragraphs.len() {
            return Err(HwpError::RenderError(format!(
                "셀 문단 인덱스 {} 범위 초과 (총 {}개)", cell_para_idx, parent_cell.paragraphs.len()
            )));
        }
        let pad_l = if parent_cell.padding.left != 0 {
            parent_cell.padding.left
        } else {
            parent_table.padding.left
        };
        let pad_r = if parent_cell.padding.right != 0 {
            parent_cell.padding.right
        } else {
            parent_table.padding.right
        };
        let cp = &parent_cell.paragraphs[cell_para_idx];
        let cs_id = cp.char_shapes.first().map(|cs| cs.char_shape_id).unwrap_or(0);
        let ps_id = cp.para_shape_id;
        (parent_cell.width, pad_l, pad_r, cs_id, ps_id)
    };

    // --- 2. 내부 표 치수 계산 (부모 셀 폭 기반) ---
    let outer_margin: i16 = 283; // ~1mm
    let outer_margin_lr = (outer_margin * 2) as i32;
    let content_width = (parent_cell_width as i32
        - parent_cell_pad_l as i32
        - parent_cell_pad_r as i32
        - outer_margin_lr)
        .max(1200) as u32; // 최소 12mm
    let col_width = content_width / col_count as u32;
    let cell_pad = crate::model::Padding { left: 510, right: 510, top: 141, bottom: 141 };
    let cell_height: u32 = (cell_pad.top + cell_pad.bottom) as u32;
    let rendered_row_height: u32 = cell_pad.top as u32 + 1000 + cell_pad.bottom as u32;
    let total_width = col_width * col_count as u32;
    let total_height = rendered_row_height * row_count as u32;

    // BorderFill: 기존 실선 재사용 또는 신규 생성
    let cell_border_fill_id = {
        let existing = self.document.doc_info.border_fills.iter().position(|bf| {
            bf.borders.iter().all(|b| b.line_type == BorderLineType::Solid && b.width >= 1)
        });
        if let Some(idx) = existing {
            (idx + 1) as u16
        } else {
            let solid_border = BorderLine { line_type: BorderLineType::Solid, width: 1, color: 0 };
            let new_bf = BorderFill {
                raw_data: None,
                attr: 0,
                borders: [solid_border, solid_border, solid_border, solid_border],
                diagonal: DiagonalLine { diagonal_type: 1, width: 0, color: 0 },
                fill: Fill::default(),
            };
            self.document.doc_info.border_fills.push(new_bf);
            self.document.doc_info.raw_stream = None;
            self.document.doc_info.border_fills.len() as u16
        }
    };

    // --- 3. 셀 목록 생성 ---
    let mut cells = Vec::with_capacity((row_count as usize) * (col_count as usize));
    for r in 0..row_count {
        for c in 0..col_count {
            let mut cell = Cell::new_empty(c, r, col_width, cell_height, cell_border_fill_id);
            cell.padding = cell_pad;
            cell.vertical_align = crate::model::table::VerticalAlign::Center;
            for cp in &mut cell.paragraphs {
                cp.char_count_msb = true;
                cp.para_shape_id = default_para_shape_id;
                if cp.raw_header_extra.len() < 10 {
                    let mut rhe = vec![0u8; 10];
                    rhe[0..2].copy_from_slice(&1u16.to_le_bytes());
                    rhe[4..6].copy_from_slice(&1u16.to_le_bytes());
                    cp.raw_header_extra = rhe;
                }
                let seg_w = (col_width as i32) - 141 - 141;
                cp.line_segs = vec![LineSeg {
                    text_start: 0,
                    line_height: 1000,
                    text_height: 1000,
                    baseline_distance: 850,
                    line_spacing: 600,
                    segment_width: seg_w,
                    tag: 0x00060000,
                    ..Default::default()
                }];
            }
            cell.raw_list_extra = Vec::new();
            cells.push(cell);
        }
    }

    // --- 4. Table 구조체 조립 ---
    let row_sizes: Vec<i16> = (0..row_count).map(|_| col_count as i16).collect();

    let flags: u32 = (2 << 3) | (3 << 8) | (4 << 15) | (2 << 18) | (1 << 21);
    let mut raw_ctrl_data = vec![0u8; 38];
    raw_ctrl_data[0..4].copy_from_slice(&flags.to_le_bytes());
    raw_ctrl_data[12..16].copy_from_slice(&total_width.to_le_bytes());
    raw_ctrl_data[16..20].copy_from_slice(&total_height.to_le_bytes());
    raw_ctrl_data[24..26].copy_from_slice(&outer_margin.to_le_bytes());
    raw_ctrl_data[26..28].copy_from_slice(&outer_margin.to_le_bytes());
    raw_ctrl_data[28..30].copy_from_slice(&outer_margin.to_le_bytes());
    raw_ctrl_data[30..32].copy_from_slice(&outer_margin.to_le_bytes());
    let instance_id: u32 = {
        let mut h: u32 = 0x7c170000;
        h = h.wrapping_add(row_count as u32 * 0x1000);
        h = h.wrapping_add(col_count as u32 * 0x100);
        h = h.wrapping_add(total_width);
        h = h.wrapping_add(total_height.wrapping_mul(0x1b));
        h = h.wrapping_add((parent_para_idx as u32).wrapping_mul(0x7));
        h = h.wrapping_add((cell_idx as u32).wrapping_mul(0x13));
        if h == 0 { h = 0x7c174b69; }
        h
    };
    raw_ctrl_data[32..36].copy_from_slice(&instance_id.to_le_bytes());

    let mut table = Table {
        attr: 0x082A2210,
        row_count,
        col_count,
        cell_spacing: 0,
        padding: crate::model::Padding { left: 510, right: 510, top: 141, bottom: 141 },
        row_sizes,
        border_fill_id: cell_border_fill_id,
        zones: Vec::new(),
        cells,
        cell_grid: Vec::new(),
        page_break: TablePageBreak::None,
        repeat_header: false,
        caption: None,
        common: crate::model::shape::CommonObjAttr {
            treat_as_char: false,
            text_wrap: crate::model::shape::TextWrap::TopAndBottom,
            vert_rel_to: crate::model::shape::VertRelTo::Para,
            horz_rel_to: crate::model::shape::HorzRelTo::Para,
            vert_align: crate::model::shape::VertAlign::Top,
            horz_align: crate::model::shape::HorzAlign::Left,
            width: total_width,
            height: total_height,
            ..Default::default()
        },
        outer_margin_left: outer_margin,
        outer_margin_right: outer_margin,
        outer_margin_top: outer_margin,
        outer_margin_bottom: outer_margin,
        raw_ctrl_data,
        raw_table_record_attr: 0x00000006,
        raw_table_record_extra: vec![0u8; 2],
        dirty: true,
    };
    table.rebuild_grid();

    // --- 5. Table을 포함하는 셀 문단 생성 ---
    let mut table_raw_header_extra = vec![0u8; 10];
    table_raw_header_extra[0..2].copy_from_slice(&1u16.to_le_bytes());
    table_raw_header_extra[4..6].copy_from_slice(&1u16.to_le_bytes());

    let inner_seg_w = (parent_cell_width as i32
        - parent_cell_pad_l as i32
        - parent_cell_pad_r as i32)
        .max(0);

    let table_para = Paragraph {
        text: String::new(),
        char_count: 9,
        char_count_msb: true,
        control_mask: 0x00000800,
        char_offsets: vec![],
        char_shapes: vec![CharShapeRef {
            start_pos: 0,
            char_shape_id: default_char_shape_id,
        }],
        line_segs: vec![LineSeg {
            text_start: 0,
            line_height: 1000,
            text_height: 1000,
            baseline_distance: 850,
            line_spacing: 600,
            segment_width: 0, // 표 문단: 0
            tag: 0x00060000,
            ..Default::default()
        }],
        para_shape_id: default_para_shape_id,
        style_id: 0,
        controls: vec![Control::Table(Box::new(table))],
        ctrl_data_records: vec![None],
        has_para_text: true,
        raw_header_extra: table_raw_header_extra,
        ..Default::default()
    };

    // --- 6. 셀 문단에 삽입 ---
    self.document.sections[section_idx].raw_stream = None;

    let insert_cell_para_idx = {
        let parent_table = match &mut self.document.sections[section_idx]
            .paragraphs[parent_para_idx].controls[control_idx] {
            Control::Table(t) => t,
            _ => return Err(HwpError::RenderError(
                "지정된 컨트롤이 표가 아닙니다".to_string()
            )),
        };
        let cell = &mut parent_table.cells[cell_idx];
        let target = &cell.paragraphs[cell_para_idx];
        let is_empty = target.text.is_empty() && target.controls.is_empty();

        let inserted_at;
        if is_empty && char_offset == 0 {
            cell.paragraphs[cell_para_idx] = table_para;
            inserted_at = cell_para_idx;
        } else if char_offset == 0 && target.controls.is_empty() {
            cell.paragraphs.insert(cell_para_idx, table_para);
            inserted_at = cell_para_idx;
        } else if char_offset > 0 && !target.text.is_empty() {
            let new_para = cell.paragraphs[cell_para_idx].split_at(char_offset);
            cell.paragraphs.insert(cell_para_idx + 1, new_para);
            cell.paragraphs.insert(cell_para_idx + 1, table_para);
            inserted_at = cell_para_idx + 1;
        } else {
            cell.paragraphs.insert(cell_para_idx + 1, table_para);
            inserted_at = cell_para_idx + 1;
        }

        // 중첩 표 뒤에 빈 문단 추가 (HWP 표준)
        let mut empty_rhe = vec![0u8; 10];
        empty_rhe[0..2].copy_from_slice(&1u16.to_le_bytes());
        empty_rhe[4..6].copy_from_slice(&1u16.to_le_bytes());
        let empty_para = Paragraph {
            text: String::new(),
            char_count: 1,
            char_count_msb: false,
            control_mask: 0,
            para_shape_id: default_para_shape_id,
            style_id: 0,
            char_shapes: vec![CharShapeRef {
                start_pos: 0,
                char_shape_id: default_char_shape_id,
            }],
            line_segs: vec![LineSeg {
                text_start: 0,
                line_height: 1000,
                text_height: 1000,
                baseline_distance: 850,
                line_spacing: 600,
                segment_width: inner_seg_w,
                tag: 0x00060000,
                ..Default::default()
            }],
            has_para_text: false,
            raw_header_extra: empty_rhe,
            ..Default::default()
        };
        cell.paragraphs.insert(inserted_at + 1, empty_para);
        parent_table.dirty = true;
        inserted_at
    };

    // --- 7. 리플로우 및 재페이지네이션 ---
    self.rebuild_section(section_idx);

    self.event_log.push(DocumentEvent::TableRowInserted {
        section: section_idx, para: parent_para_idx, ctrl: control_idx,
    });
    Ok(super::super::helpers::json_ok_with(&format!(
        "\"cellParaIdx\":{},\"controlIdx\":0", insert_cell_para_idx
    )))
}

/// 커서 위치에 그림을 삽입한다 (네이티브).
pub fn insert_picture_native(
